/** UsptBsnsPlanDocDao.insert */
insert into uspt_bsns_plan_doc
	 (
		 bsns_plan_doc_id
		,bsns_slctn_id
		,task_nm_ko
		,task_nm_en
		,apply_field
		,prsentr_id
		,presentn_dt
		,prsentr_attachment_group_id
		,makeup_req_cn
		,makeup_rqester_id
		,makeup_req_dt
		,makeup_req_file_group_id
		,plan_presentn_sttus_cd
		,partcptn_company_cnt
		,smlpz_cnt
		,mspz_cnt
		,etc_cnt
		,total_wct
		,member_id
		,creator_id
		,created_dt
		,updater_id
		,updated_dt
	) values (
		 #{bsnsPlanDocId}
		,#{bsnsSlctnId}
		,#{taskNmKo}
		,#{taskNmEn}
		,#{applyField}
		,#{prsentrId}
		,#{presentnDt}
		,#{prsentrAttachmentGroupId}
		,#{makeupReqCn}
		,#{makeupRqesterId}
		,#{makeupReqDt}
		,#{makeupReqFileGroupId}
		,#{planPresentnSttusCd}
		,#{partcptnCompanyCnt}
		,#{smlpzCnt}
		,#{mspzCnt}
		,#{etcCnt}
		,#{totalWct}
		,#{memberId}
		,#{creatorId}
		,#{createdDt}
		,#{updaterId}
		,#{updatedDt}
)

mapper.update:
/** UsptBsnsPlanDocDao.update */
update uspt_bsns_plan_doc
	  set   task_nm_ko               		= #{taskNmKo}
			,task_nm_en                	= #{taskNmEn}
			,apply_field               		= #{applyField}
			,prsentr_id                		= #{prsentrId}
			,presentn_dt               		= #{presentnDt}
			,prsentr_attachment_group_id = #{prsentrAttachmentGroupId}
			,makeup_req_cn             	= #{makeupReqCn}
			,makeup_rqester_id         	= #{makeupRqesterId}
			,makeup_req_dt             	= #{makeupReqDt}
			,makeup_req_file_group_id  = #{makeupReqFileGroupId}
			,plan_presentn_sttus_cd    	= #{planPresentnSttusCd}
			,partcptn_company_cnt     = #{partcptnCompanyCnt}
			,smlpz_cnt                 		= #{smlpzCnt}
			,mspz_cnt                  		= #{mspzCnt}
			,etc_cnt                   		= #{etcCnt}
			,total_wct                 		= #{totalWct}
			,member_id						= #{memberId}
			,updater_id                		= #{updaterId}
			,updated_dt                	= #{updatedDt}
	where bsns_plan_doc_id = #{bsnsPlanDocId}
	    and bsns_slctn_id = #{bsnsSlctnId}

