mapper.select:
/** UsptBsnsPlanDocDao.selectList */ select bsns_plan_doc_id ,bsns_slctn_id ,task_nm_ko ,task_nm_en ,apply_field ,prsentr_id ,presentn_dt ,prsentr_attachment_group_id ,makeup_req_cn ,makeup_rqester_id ,makeup_req_dt ,makeup_req_file_group_id ,plan_presentn_sttus_cd ,partcptn_company_cnt ,smlpz_cnt ,mspz_cnt ,etc_cnt ,total_wct ,member_id ,creator_id ,created_dt ,updater_id ,updated_dt from uspt_bsns_plan_doc where 1=1
and bsns_plan_doc_id = #{bsnsPlanDocId}
and bsns_slctn_id = #{bsnsSlctnId}
and plan_presentn_sttus_cd = #{planPresentnSttusCd}
and taskNmKo #{taskNmKo}
and presentn_dt between #{presentnDtStart} and #{presentnDtEnd}
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptBsnsPlanDocDao.selectBsnsPlanBaseDocInfo */ select ub.bsns_nm /*사업명*/ , ub.bsns_year /*사업년도*/ , ub.cnsrtm /*컨소시엄여부*/ , ubpa.receipt_no /*접수번호*/ , ubp.pblanc_nm /*공고명*/ , ubp.bsns_bgnde /*사업시작일*/ , ubp.bsns_endde /*사업종료일*/ , case when ubpd.task_nm_ko is null then ubpat.task_nm_ko else ubpd.task_nm_ko end as task_nm_ko /*과제명*/ , case when ubpd.task_nm_en is null then ubpat.task_nm_en else ubpd.task_nm_en end as task_nm_en /*과제명_영문*/ , case when ubpd.apply_field is null then ubpat.apply_realm_id else ubpd.apply_field end as apply_field /*지원분야*/ , to_char(ubpd.presentn_dt ,'yyyymmdd') as presentn_dy /*제출일*/ , ubpd.presentn_dt /*제출일시*/ , ubpd.plan_presentn_sttus_cd /*제출상태*/ , case when ubpd.plan_presentn_sttus_cd is null then '미제출' else fn_cmm_get_code_nm('PLAN_PRESENTN_STTUS', ubpd.plan_presentn_sttus_cd) end as plan_presentn_sttus_nm /*제출상태명*/ , ubpat.apply_id /*신청ID*/ , ubs.bsns_slctn_ID /*사업선정대상ID */ , ubpd.bsns_plan_doc_id /*사업계획서ID*/ , coalesce(ubpd.partcptn_company_cnt,0) as partcptn_company_cnt /** 참여기업수 */ , coalesce(ubpd.smlpz_cnt,0) as smlpz_cnt /** 중소기업수 */ , coalesce(ubpd.mspz_cnt,0) as mspz_cnt /** 중견기업수 */ , coalesce(ubpd.etc_cnt,0) as etc_cnt /** 기타수 */ , ubpd.prsentr_attachment_group_id /** 제출첨부파일그룹ID */ , case when ubpd.member_id is null then ubpa.member_id else ubpd.member_id end as member_id /*회원ID*/ from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_job_step ubjs /*사업업무단계*/ on ubp.bsns_cd = ubjs.bsns_cd and ubjs.job_step_cd ='AGREM' /*업무단계_협약*/ inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id inner join uspt_bsns_pblanc_apply_task ubpat /**사업공고 신청 과제*/ on ubpa.apply_id = ubpat.apply_id inner join uspt_last_slctn_trget ulst /**최종선정대상*/ on ubpa.apply_id = ulst.apply_id and ulst.slctn = true inner join uspt_bsns_slctn ubs /**사업선정대상*/ on ulst.last_slctn_trget_id = ubs.last_slctn_trget_id left outer join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubs.bsns_slctn_id = ubpd.bsns_slctn_id
and ubpd.bsns_plan_doc_id = #{bsnsPlanDocId} /*사업계획서ID*/
where 1=1 and ubs.bsns_slctn_id =#{bsnsSlctnId} /*사업선정대상ID*/

