/** UsptBsnsPlanDocDao.updateResnInfo */
update uspt_bsns_plan_doc
	  set  makeup_req_cn             	= #{makeupReqCn}
			,makeup_rqester_id         	= #{makeupRqesterId}
			,makeup_req_dt             	= #{makeupReqDt}
			,makeup_req_file_group_id  = #{makeupReqFileGroupId}
			,plan_presentn_sttus_cd    	= #{planPresentnSttusCd}
			,updater_id                		= #{updaterId}
			,updated_dt                	= #{updatedDt}
	where bsns_plan_doc_id = #{bsnsPlanDocId}
	    and bsns_slctn_id = #{bsnsSlctnId}

/** UsptBsnsPlanDocDao.updatePlanSttus */
update uspt_bsns_plan_doc
	  set  plan_presentn_sttus_cd    	= #{planPresentnSttusCd}
			,updater_id                		= #{updaterId}
			,updated_dt                	= #{updatedDt}
	where bsns_plan_doc_id = #{bsnsPlanDocId}
	   and bsns_slctn_id = #{bsnsSlctnId}

/** UsptBsnsPlanDocDao.updateTaskInfo */
update uspt_bsns_plan_doc
	  set  task_nm_ko 		= #{taskNmKo}	/*과제명*/
		   ,task_nm_en         = #{taskNmEn}	/*과제명_영문*/
		   ,apply_field          = #{applyField}	/*지원분야*/
		   ,updater_id          = #{updaterId}
		   ,updated_dt         = #{updatedDt}
	where bsns_plan_doc_id 	= #{bsnsPlanDocId}

/** UsptBsnsPlanDocDao.updatePrtcmpnyCnt */
update uspt_bsns_plan_doc
	  set 	partcptn_company_cnt     = #{partcptnCompanyCnt}
	        ,smlpz_cnt              	= #{smlpzCnt}
			,mspz_cnt               = #{mspzCnt}
			,etc_cnt                  = #{etcCnt}
		    ,updater_id            	= #{updaterId}
		    ,updated_dt         	= #{updatedDt}
	where bsns_plan_doc_id 	= #{bsnsPlanDocId}
